SELECT count(*) FROM movie_companies, title, company_type, movie_info, company_name, info_type, cast_info, name WHERE movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_info.movie_id = title.id AND movie_companies.company_id = company_name.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id;